import { Handler } from "mitt";
import { eventBus } from "../const";

export enum BREADCRUMB_EVENT {
    UPDATE_BREADCRUMB_ITEMS = 'UPDATE_BREADCRUM_ITEMS',
}

export interface BreadcrumbProps {
    title: React.ReactNode;
}

export const breadcrumbEventBus = {
    updateBreadcrumb: (payload: BreadcrumbProps[]) => {
        eventBus.emit(BREADCRUMB_EVENT.UPDATE_BREADCRUMB_ITEMS, payload);
    },
    onUpdateBreadcrumb: (handler: (payload: BreadcrumbProps[]) => void) => {
        eventBus.on(BREADCRUMB_EVENT.UPDATE_BREADCRUMB_ITEMS, handler as any);
    },
    offUpdateBreadcrumb: (handler?: (payload: BreadcrumbProps[]) => void) => {
        eventBus.off(BREADCRUMB_EVENT.UPDATE_BREADCRUMB_ITEMS, handler as any);
    },
};
